struct Data {
    pairs: Vec<(i32, i32)>,
}

impl Data {
    fn new() -> Self {
        let mut pairs = vec![];
        for i in 0..10 {
            pairs.push((i, i * 2));
        }
        Data { pairs }
    }

    fn split_pairs(&self) -> (Vec<i32>, Vec<i32>) {
        let mut xs = vec![];
        let mut ys = vec![];
        for &(x, y) in self.pairs.iter() {
            xs.push(x);
            ys.push(y);
        }
        (xs, ys)
    }
}

fn main() {
    let data = Data::new();
    let (xs, ys) = data.split_pairs();
    println!("xs: {:?}\ny: {:?}", xs, ys);
}
